INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Bhilai', 'overview', 'Overview > Languages spoken: All languages in college, Hindi and local language in the state.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Bhilai', 'overview', 'Overview > Climate: High temperatures, low rain, dry weather.');
