INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'fines', 'Fines > Disciplinary: SSAC (disciplinary committee) handles issues. Punishments include: social hours (charity work), semester back, year back, removing from hostel (stay off campus).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'fines', 'Fines > Offenses: Property damage, cheating, causing problems to others.');
