INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'language_climate', 'Language Climate > Climate: Winters 8-25Â°C, Summers 25-40Â°C. Very humid - sometimes low temperature feels hot. Winters can feel very cold too.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'academics', 'Academics > Curriculum: UG Curriculum has Institute Level Plan. 1st sem: Foundation Programme, Intro to Writing, World Civilizations, Calculus, Engineering Graphics, Computing, Design Innovation & Prototyping, Materials for Future, PE. 2nd sem: General Education, Writing II, Differential Equations, Undergrad Science Lab, Data Centric Computing, Probability & Statistics, Electrical Engineering, World of Engineering, PE. Branch-specific courses start from 3rd semester. Students can choose Sci/Math baskets and electives from a given list.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'academics', 'Academics > Credits: 28 credits in 1st sem, 22 in 2nd sem, reducing to 8-10 in later semesters as electives increase.');
