INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Palakkad', 'elections', 'Elections > 10 positions: Students General Secretary (x2), Academic Affairs Secretary, Media and Cultural Affairs Secretary, Hostel Affairs Secretary (x2), Sports Affairs Secretary, Technical Affairs Secretary, Post Graduate Affairs Secretary, Research Affairs Secretary.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Palakkad', 'laundry', 'Laundry > Free washing machines available in every hostel at IIT Palakkad. Each hostel has a separate washing machine room.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Palakkad', 'sports', 'Sports > Outdoor: Cricket ground, Football ground, Basketball court, and Volleyball court at IIT Palakkad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Palakkad', 'sports', 'Sports > Indoor: Badminton courts, Table Tennis, and Chess at IIT Palakkad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Palakkad', 'canteen', 'Canteen > Amul: 10 am to 7 pm at IIT Palakkad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Palakkad', 'canteen', 'Canteen > Nescafe: 9 am to 12 pm at IIT Palakkad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Palakkad', 'canteen', 'Canteen > 3 local canteens: 8 am to 12 pm at IIT Palakkad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Palakkad', 'shops', 'Shops > New City Mart and Ezee Mart near IIT Palakkad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Palakkad', 'fines', 'Fines > Rs 500 per day for coming late to college after semester holiday at IIT Palakkad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Palakkad', 'gym', 'Gym > 2 gyms available at IIT Palakkad, all free, for both boys and girls.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Palakkad', 'medical', 'Medical > Medical insurance provided at IIT Palakkad. Covers 100+ hospitals all over India, free of cost.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'overview', 'Overview > Full Name: Indian Institute of Technology Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'overview', 'Overview > Location: Bihta, Patna, Bihar 801106.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'overview', 'Overview > Languages spoken: Bhojpuri, Hindi, and English (English mostly on campus only).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'overview', 'Overview > Climate: Summer 35-45C with heatwaves. Monsoon has moderate to heavy rain. Winter 5-15C with fog. Spring and Autumn are pleasant. Weather described as pretty weird and confusing.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'transport', 'Transport > Airport: Accessible via cabs, autos, and buses from IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'transport', 'Transport > Railway: Bihta is the nearest railway station to IIT Patna. Danapur and Patna Junction are also options.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'transport', 'Transport > Bus: Patna Bus Stand and Pataliputra Bus Stand serve IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'transport', 'Transport > Cab Services: Ola and Uber are available at IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'restaurants', 'Restaurants > On Campus: Food Court inside IIT Patna campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'restaurants', 'Restaurants > Bihta: Banjara, Shahi Darbar, Bihari Thaath.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'restaurants', 'Restaurants > Cafes: Chai Sutta Bar, Momo cafes near IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'restaurants', 'Restaurants > Patna City: Pista House, Barkaas.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'nearby_places', 'Nearby Places > Patna: Golghar, Buddha Smriti Park, Patna Museum, Marine Drive.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'nearby_places', 'Nearby Places > Weekend Trips: Rajgir, Nalanda, Bodh Gaya.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'nearby_places', 'Nearby Places > Long Trips: Sikkim, Darjeeling, Mussoorie, Rishikesh, Delhi, Jaipur, Kolkata.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'nearby_places', 'Nearby Places > Near Campus: Bihta surroundings and temples.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'nearby_places', 'Nearby Places > Shopping: P&M Mall, City Centre Patna, Vasundhara Metro Mall in Patna. V-Mart in Bihta.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'hostels', 'Hostels > Boys: CV Raman Hostel (3 per room, for 1st year boys).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'hostels', 'Hostels > Boys: Aryabhatta Hostel A+B (2 per room, for 2nd year boys).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'hostels', 'Hostels > Boys: Kalam Hostel C+D (2 per room, for 3rd and 4th year boys).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'hostels', 'Hostels > Boys Summary: 3 boys hostels at IIT Patna. 1st years in CV Raman (3-sharing). 2nd years in Aryabhatta A+B (2-sharing). 3rd/4th years in Kalam C+D (2-sharing).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'hostels', 'Hostels > Girls: Aryabhatta Hostel (for 1st year girls).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'hostels', 'Hostels > Girls: Asima Hostel (for 2nd year and 3rd/4th year girls).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'hostels', 'Hostels > Girls Summary: 2 girls hostels at IIT Patna. 1st years in Aryabhatta, seniors in Asima.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'mess', 'Mess > Assignment: Each hostel has its own separate mess at IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'mess', 'Mess > 1st Years: All 1st year students eat in the CV Raman mess (combined).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'laundry', 'Laundry > Each hostel block has separate laundry facilities at IIT Patna. Laundry is paid from this year.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'laundry', 'Laundry > External laundry service "Cleanologist" is available outside the hostel at IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'elections', 'Elections > Elections are held for 1st, 2nd, and 3rd year students at IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'elections', 'Elections > Positions: Sports Secretary, HoSCA (Head of Student Cultural Affairs, for culturals), SWB (Student Welfare Board), AIR (Alumni and Industrial Relations, new position for 3rd to 4th year), Hostel Affairs Secretary.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'elections', 'Elections > Vice President position is only for students going to 4th year and requires having held a position before.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'sports', 'Sports > Available: Cricket, Volleyball, Badminton, Basketball, Table Tennis, Lawn Tennis, Football, Hockey, Chess, Carrom Board.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'canteen', 'Canteen > Food Court on campus with 2 food shops and 1 grocery/snacks shop at IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'canteen', 'Canteen > Additional shops are available outside Gate 1 of IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'medical', 'Medical > IIT Patna has an institute hospital with ambulance facility, though it is far from the hostels.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'medical', 'Medical > NSMCH (Medical College Hospital) is located outside campus. Students show ID card, pay first, then get reimbursed via a form.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'fee_structure', 'Fee Structure > 1st Semester Total (Indian): Rs 1,64,750. Includes one-time refundable deposits of Rs 20,000 (Campus Amenities) and Rs 5,000 (Hostel).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'fee_structure', 'Fee Structure > 1st Semester Breakdown: Academic Rs 10,750 + Tuition Rs 1,00,000 + Hostel Rs 6,500 + Other Institute Rs 14,000 + Gymkhana Rs 5,000 + Transport Rs 1,500 + Health Insurance Rs 2,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'fee_structure', 'Fee Structure > International Students: Rs 3,64,750 for 1st semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'fee_structure', 'Fee Structure > 2nd Semester Onwards (Indian): Rs 1,25,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'fee_structure', 'Fee Structure > SC/ST/PH students: Tuition fee exempted. Family income below 1 lakh: full fee remission. Family income 1-5 lakh: 2/3rd fee remission.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'attendance', 'Attendance > 75% attendance is mandatory per semester per course at IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'attendance', 'Attendance > Below 75% means not eligible for exam and student must do a summer term. Valid medical reasons are accepted.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'wifi', 'WiFi > WiFi is available in all hostels at IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'wifi', 'WiFi > LAN is available in CV Raman and Aryabhatta hostels. Kalam hostel has WiFi only (no LAN).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'wifi', 'WiFi > 5G is available at IIT Patna. Network is poor in academic departments but WiFi is available there.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'fests', 'Fests > Celesta (tech fest) at IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'fests', 'Fests > Anwesha (cultural fest) at IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'fests', 'Fests > Infinito (sports fest) at IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'fests', 'Fests > TEDx is organized at IIT Patna.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'clubs', 'Clubs > HoSCA (Cultural): Exousia, Aria, Quiz Club, Vincestroke, Yavanika, Anime Club, HOOT, Hexachrome, Pixxel, Syahi.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'clubs', 'Clubs > STC (Technical): Tinkerers Lab, Robocon IITP, MoodBoard Design, Sparkonics, Astronomy & Particle Physics Club, NJACK-ML, NJACK-CP, NJACK-Dev, NJACK-CyberSec, ChessX, IITPMotorsports, Finance Club, MatES.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'clubs', 'Clubs > Sports: Athletics, Badminton, Basketball, Cricket, Chess, Football, Table Tennis, Lawn Tennis, Volleyball, Squash, Weightlifting/Powerlifting, Skating.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'language', 'Language > Bhojpuri, Hindi, and English are spoken around IIT Patna. English is used mostly on campus only.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Patna', 'climate', 'Climate > Summer: 35-45C with heatwaves. Monsoon: moderate to heavy rain. Winter: 5-15C with fog. Spring/Autumn: pleasant. Weather is described as pretty weird and confusing.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'overview', 'Overview > NIT Agartala is a National Institute of Technology located in Jirania, Tripura, India.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'overview', 'Overview > Location: State Tripura, District West Tripura, Pincode 799046.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'hostels_boys', 'Hostels Boys > Aryabhatta Hostel for boys. 2-sharing per room. From 3rd year, single room for boys.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'hostels_boys', 'Hostels Boys > RNT Hostel for boys. 2-sharing per room. From 3rd year, single room for boys.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'hostels_girls', 'Hostels Girls > Gargi Hostel for girls. 2-sharing per room.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'mess', 'Mess > No detailed mess menu provided by ambassador. Data gap — needs follow-up.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fee_structure', 'Fee Structure > Source: Student fee receipt for OBC/NCL category student (2024-29 batch, Electronics & Instrumentation Engineering). General category tuition fee is NOT available from this receipt.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fee_structure', 'Fee Structure > 1st Semester Total (OBC/NCL student): Rs 37,125. This includes all fees below. Tuition fee appears as Rs 0 for this student, likely due to fee waiver for OBC/NCL category.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fee_structure', 'Fee Structure > Institute Development Fee: Rs 9,500 per semester (ranges Rs 9,400-9,500 across semesters).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fee_structure', 'Fee Structure > Medical Fee: Rs 1,200 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fee_structure', 'Fee Structure > Student Activity Fund: Rs 1,000 per semester (some semesters Rs 190).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fee_structure', 'Fee Structure > Gymkhana/Sports Fee: Rs 300 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fee_structure', 'Fee Structure > Grade Card Fee: Rs 500 per semester (varies: Rs 334 in 3rd semester).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fee_structure', 'Fee Structure > One-time fees at admission: Admission Fee Rs 1,000, Caution Money Rs 6,000 (refundable), Prospectus Fee Rs 200.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fee_structure', 'Fee Structure > Convocation Fee: Rs 1,500 (charged in 8th semester only).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fee_structure', 'Fee Structure > All Other Fees: Varies between Rs 2,425 and Rs 2,975 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fee_structure', 'Fee Structure > Computerization/SBI/Electricity Fee: Varies from Rs 0 to Rs 1,085 depending on semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fee_structure', 'Fee Structure > Late fee fine: Rs 5,000 for first five days late, Rs 10,000 after that.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'wifi', 'WiFi > 2 GB per day for phone. 3 GB per day for laptop (college provides). Network is mostly 5G, sometimes 4G.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'attendance', 'Attendance > 75% attendance is not mandatory or compulsory. If requested, students can still write semester examinations.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'clubs', 'Clubs > Team Xantronz, Robotics Club, DSA Club, Anima Club, We Can, Think India, TRIAC Club, Dizire Club, Pixcles Club.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fests', 'Fests > Moksha is the tech fest of NIT Agartala.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'sports', 'Sports > Available: Cricket, Hockey, Volleyball, Kabaddi, Football, Badminton, Kho-Kho, Basketball, Table Tennis, Tennis.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'canteen', 'Canteen > Nescafe cafe inside hostel, open from evening to night. Food court available in college.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'canteen', 'Canteen > Many shops available near campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'laundry', 'Laundry > No washing machines in college. Outside laundry service available, students have to pay.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'elections', 'Elections > No student elections in NIT Agartala.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'gym', 'Gym > Boys and girls have separate gyms. Free — no need to pay.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'medical', 'Medical > Hospital available on campus. In emergency, ambulance takes students to outside hospital. Medical fee: Rs 1,200 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'transport', 'Transport > Nearest airport: Bir Bikram Airport, Agartala (28 km). Nearest railway station: Jirania Railway Station (3.1 km). Nearest bus stand: Jirania Bus Stand (4 km).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'restaurants', 'Restaurants > John Restaurant and Mark Restaurant are near campus. No Swiggy or Zomato available inside or near college.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'nearby_places', 'Nearby Places > Nearby tourist spots: Ujantha Palace, Mongtang Valley, Tripura Sundari.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'nearby_places', 'Nearby Places > Far tourist spots (100-150 km): Unnakoti, Jampui Hills, Coconut Island, Dumboor Waterfalls.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'nearby_places', 'Nearby Places > Malls: Polo Central Mall, ML Plaza, Agartala City Center.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'language_climate', 'Language > Home state language is Bengali. Languages often used on campus: Telugu, Hindi, English.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'language_climate', 'Climate > Mostly sunny and rainy.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'fines', 'Fines > Semester late fee: Rs 5,000 for first five days late. Rs 10,000 after that.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'academics', 'Academics > 2nd Semester UG subjects: Physics-II, Chemistry-II, Mathematics-II, Engineering Graphics, IP Theory (Introduction to Programming), DSTM, Basic Electronics, Basic Electrical Engineering, Engineering Mechanics, English, Workshop Practice.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'academics', 'Academics > Timetable has 12 sections (A to L) divided into Group-I (A-F) and Group-II (G-L). Classes run 9AM-5PM with lunch break 1-2PM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'academics', 'Academics > Labs include Physics Lab, Chemistry Lab (2 labs), Basic Electronics Lab, Basic Electrical Engineering Lab, IP Lab, Workshop Practices.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Agartala', 'academics', 'Academics > First Year Coordinator: Dr. Sadhan Gope. Multiple faculty from Electrical, Electronics, CSE, Mechanical, Civil, Math, Physics, Chemistry, English departments.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Bhopal', 'overview', 'Overview > Facts: Maulana Azad National Institute of Technology (MANIT) Bhopal is located in Madhya Pradesh, Bhopal, PIN 462003.');
