INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'fee_structure', 'Fee Structure > Hostel Fee (New Admission) Establishment Charges: Maintenance Rs 120, Student Concession Fund Rs 150, Mess Concession Fund Rs 150, GOEM (General Amenities and Equipment Fund) Rs 550, Students Medical Relief Fund Rs 100, V.P. Fund Rs 250, Winner-cadre overhead Rs 1,000, Security Rs 20, Student Contingency Fund Rs 70, Games/T.A.S.K Fund Rs 70, Diwali Fund Rs 30, Hostel Day Celebrations Rs 70, Recreation committee (cultural event) Rs 130, Miscellaneous Rs 20.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'fee_structure', 'Fee Structure > Hostel Fee (New Admission) Total Fee Rs 3,900. Mess Advance Rs 22,000. Grand Total for new admission Rs 25,300.');
