INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'attendance', 'Attendance > Minimum 75% attendance required for end-semester exams at NITK Surathkal.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'attendance', 'Attendance > The 75% requirement can be relaxed up to 65% by the Director.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'attendance', 'Attendance > An extra 5% relaxation is possible beyond the 65% threshold.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'attendance', 'Attendance > Medical exigency can further relax attendance requirement to 50%.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'attendance', 'Attendance > Students below 65% attendance are marked "Detained" and are not allowed to sit for the end-semester exam.');
